import stylesText from './nutrition-edit.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import { MEAL_TYPES } from '@motivation/shared';
import type { ConsumptionEntry, FoodItem, MealType, NewConsumptionEntry } from '@motivation/shared';
import { consumptionEntryToFormData } from '../food-serving-form/food-serving-form.types.js';
import '../food-serving-form/food-serving-form.component.js';
import '../food-thumbnail/food-thumbnail.component.js';
import type { FoodServingForm } from '../food-serving-form/food-serving-form.component.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="edit-container">
        <div class="edit-header">
            <food-thumb id="food-thumb" alt=""></food-thumb>
            <div class="edit-header-text">
                <h3>Edit Entry</h3>
                <span class="source-badge" id="source-badge"></span>
            </div>
        </div>

        <input type="text" id="food-name" class="food-name-input" placeholder="Food name" readonly>

        <food-serving-form id="serving-form" editable></food-serving-form>

        <div class="form-row">
            <div class="form-group">
                <label for="meal-type">Meal</label>
                <select id="meal-type" class="form-select">
                    ${MEAL_TYPES.map(m => `<option value="${m}">${m}</option>`).join('\n                    ')}
                </select>
            </div>
            <div class="form-group">
                <label for="date">Date</label>
                <input type="date" id="date" class="form-input">
            </div>
        </div>

        <div class="action-buttons">
            <button class="btn-delete" id="btn-delete">Delete</button>
            <button class="btn-save" id="btn-save">Save</button>
        </div>
    </div>
`;

const SOURCE_LABELS: Record<string, string> = {
    manual: 'Manual',
    openfoodfacts: 'Open Food Facts',
    ai_estimate: 'AI Estimate',
    mfp_import: 'MFP Import',
};

/**
 * Edit a consumption entry. The food_item is shown for context but cannot be
 * changed here — to log a different food, the user deletes this entry and
 * creates a new one. Editable fields: meal_type, date, amount, and per-entry
 * macro overrides.
 */
export class NutritionEdit extends HTMLElement {
    private _entry: ConsumptionEntry | null = null;
    private _foodItem: FoodItem | null = null;
    private _onSave: ((id: string, updates: Partial<NewConsumptionEntry>) => void) | null = null;
    private _onDelete: ((id: string) => void) | null = null;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        const shadow = this.shadowRoot!;
        shadow.getElementById('btn-save')!.addEventListener('click', () => this.handleSave());
        shadow.getElementById('btn-delete')!.addEventListener('click', () => this.handleDelete());
        if (this._entry && this._foodItem) {
            this.populateForm();
        }
    }

    set onSave(handler: (id: string, updates: Partial<NewConsumptionEntry>) => void) {
        this._onSave = handler;
    }

    set onDelete(handler: (id: string) => void) {
        this._onDelete = handler;
    }

    set entry(val: ConsumptionEntry) {
        this._entry = val;
        if (this.isConnected && this._foodItem) {
            this.populateForm();
        }
    }

    get entry(): ConsumptionEntry | null {
        return this._entry;
    }

    set foodItem(val: FoodItem) {
        this._foodItem = val;
        if (this.isConnected && this._entry) {
            this.populateForm();
        }
    }

    private populateForm(): void {
        const e = this._entry;
        const item = this._foodItem;
        if (!e || !item) return;
        const shadow = this.shadowRoot!;

        shadow.getElementById('source-badge')!.textContent = SOURCE_LABELS[item.source] ?? item.source;
        const thumb = shadow.getElementById('food-thumb')!;
        if (item.image_path) thumb.setAttribute('path', item.image_path);
        else thumb.removeAttribute('path');
        thumb.setAttribute('alt', item.display_name);
        (shadow.getElementById('food-name') as HTMLInputElement).value = item.display_name;
        (shadow.getElementById('meal-type') as HTMLSelectElement).value = e.meal_type;
        (shadow.getElementById('date') as HTMLInputElement).value = e.date;

        const form = shadow.getElementById('serving-form') as FoodServingForm;
        form.data = consumptionEntryToFormData(e, item);
    }

    private handleSave(): void {
        if (!this._entry || !this._onSave) return;
        const shadow = this.shadowRoot!;

        const form = shadow.getElementById('serving-form') as FoodServingForm;
        const { servingAmount, serving } = form.getCurrentValues();

        const updates: Partial<NewConsumptionEntry> = {
            meal_type: (shadow.getElementById('meal-type') as HTMLSelectElement).value as MealType,
            date: (shadow.getElementById('date') as HTMLInputElement).value,
            amount: servingAmount,
            ...serving,
        };

        this._onSave(this._entry.id, updates);
    }

    private handleDelete(): void {
        if (!this._entry || !this._onDelete) return;
        const name = this._foodItem?.display_name ?? 'this entry';
        if (confirm(`Delete "${name}"?`)) {
            this._onDelete(this._entry.id);
        }
    }
}

customElements.define('nutrition-edit', NutritionEdit);
